import { useEffect, useRef, useState, useCallback } from 'react';

const WS_BASE = 'ws://localhost:8000/ws/chat';

export function useChatWebSocket(roomId, onMessage) {
  const wsRef        = useRef(null);
  const [connected, setConnected] = useState(false);
  const reconnectRef = useRef(null);
  const mountedRef   = useRef(true);

  const connect = useCallback(() => {
    if (!roomId) return;
    const token = localStorage.getItem('access_token');
    if (!token) return;

    const ws = new WebSocket(`${WS_BASE}/${roomId}/?token=${token}`);
    wsRef.current = ws;

    ws.onopen = () => {
      if (mountedRef.current) setConnected(true);
    };

    ws.onmessage = (e) => {
      try {
        const data = JSON.parse(e.data);
        if (mountedRef.current) onMessage(data);
      } catch {}
    };

    ws.onclose = () => {
      if (mountedRef.current) {
        setConnected(false);
        // Reconnect after 3s
        reconnectRef.current = setTimeout(() => {
          if (mountedRef.current) connect();
        }, 3000);
      }
    };

    ws.onerror = () => {
      ws.close();
    };
  }, [roomId, onMessage]);

  useEffect(() => {
    mountedRef.current = true;
    connect();
    return () => {
      mountedRef.current = false;
      clearTimeout(reconnectRef.current);
      if (wsRef.current) {
        wsRef.current.onclose = null;
        wsRef.current.close();
      }
    };
  }, [connect]);

  const send = useCallback((data) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(data));
    }
  }, []);

  const sendTyping = useCallback((typing) => {
    send({ action: 'typing', typing });
  }, [send]);

  const sendMessage = useCallback((content) => {
    send({ action: 'message', content });
  }, [send]);

  const sendPrescription = useCallback((prescriptionId, content) => {
    send({ action: 'prescription', prescription_id: prescriptionId, content });
  }, [send]);

  const markRead = useCallback(() => {
    send({ action: 'mark_read' });
  }, [send]);

  return { connected, sendMessage, sendTyping, sendPrescription, markRead };
}
